const sd = $getWorkflowStaticData('global');
sd.stufen = sd.stufen || {};
const setup = $('⚙️ Setup').first().json;
const checkouts = $json.checkouts || [];
const jetzt = Date.now();
const raus = [];

for (const c of checkouts) {
  if (!c.email) continue;
  const alterH = (jetzt - new Date(c.created_at).getTime()) / 3600000;
  const eintrag = sd.stufen[c.id] || { stufe: 0, ts: jetzt };

  // Welche Stufe ist jetzt faellig?
  let stufe = 0;
  if (alterH >= 72 && eintrag.stufe < 3) stufe = 3;
  else if (alterH >= 24 && eintrag.stufe < 2) stufe = 2;
  else if (alterH >= 1 && eintrag.stufe < 1) stufe = 1;
  if (stufe === 0) continue;
  if (alterH > 96) continue; // zu alt, Sequenz beendet

  const artikel = (c.line_items || []).map(li => li.quantity + 'x ' + li.title).join(', ');
  const vorname = (c.customer && c.customer.first_name) || '';
  const basis = 'Du bist E-Mail-Marketing-Profi fuer den Onlineshop "' + setup.SHOP_NAME + '".\n' +
    'Kunde: ' + (vorname || 'unbekannt (neutral anreden)') + ' | Warenkorb: ' + artikel + ' | Wert: ' + c.total_price + ' ' + c.currency + ' | Checkout-Link: ' + c.abandoned_checkout_url + '\n\n';

  let anweisung = '';
  if (stufe === 1) {
    anweisung = 'STUFE 1 (1h nach Abbruch - sanfte Erinnerung, KEIN Rabatt!):\n' +
      'Schreibe eine kurze, hilfsbereite Erinnerung auf Deutsch (Du-Form), max 80 Woerter. Ton: "Dein Warenkorb wartet auf dich - gab es ein Problem beim Bestellen? Antworte einfach auf diese Mail, wir helfen sofort." Kein Verkaufsdruck, wirkt wie aufmerksamer Service. EIN Button (als <a> mit Inline-Button-Styling) zurueck zum Checkout.';
  } else if (stufe === 2) {
    anweisung = 'STUFE 2 (24h nach Abbruch - jetzt kommt der Anreiz):\n' +
      'Schreibe eine Rueckhol-Mail auf Deutsch (Du-Form), max 110 Woerter. Jetzt den Rabattcode ' + setup.RABATT_CODE + ' (' + setup.RABATT_PROZENT + '%) prominent als kleines Dankeschoen anbieten, Code 48h gueltig. Beziehe dich charmant darauf, dass die Artikel noch reserviert sind. EIN Button zum Checkout.';
  } else {
    anweisung = 'STUFE 3 (72h nach Abbruch - letzte Chance):\n' +
      'Schreibe die finale Mail auf Deutsch (Du-Form), max 90 Woerter. Ehrliche letzte Erinnerung: Der Code ' + setup.RABATT_CODE + ' laeuft heute ab, danach raeumen wir den Warenkorb. Echte Dringlichkeit ohne Drama, ein Hauch Humor erlaubt ("wir wollen ja nicht anhaenglich wirken, aber..."). EIN Button zum Checkout.';
  }

  const prompt = basis + anweisung + '\nMobiltaugliches HTML mit Inline-CSS. Antworte NUR mit validem JSON, ohne Markdown-Codeblock: {"betreff": "...", "html": "..."}';

  raus.push({ json: { checkout_id: c.id, email: c.email, stufe, prompt } });
  sd.stufen[c.id] = { stufe, ts: jetzt };
}

// Aufraeumen: Eintraege aelter als 7 Tage loeschen
for (const [id, e] of Object.entries(sd.stufen)) {
  if (jetzt - e.ts > 7 * 24 * 3600000) delete sd.stufen[id];
}
return raus;

const blocks = $json.content || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { betreff: 'Dein Warenkorb wartet 🛒', html: text };
}
const orig = $('🧠 Stufen-Logik (1h/24h/72h)').item.json;
const setup = $('⚙️ Setup').first().json;
const empfaenger = setup.TEST_MODE === 'ja' ? setup.OWNER_EMAIL : orig.email;
return { json: {
  empfaenger,
  betreff: (setup.TEST_MODE === 'ja' ? '[TEST · Stufe ' + orig.stufe + '] ' : '') + daten.betreff,
  email_html: daten.html
}};
